
# -*- coding: utf-8 -*-
import os,sys,base64,json,hashlib,hmac

def _u(x):
    try:
        o=json.loads(x); return o["h"][o["i"]]
    except: return ""

A = base64.b64decode("ZTRHNXl0dTQ=").decode()

p=os.path.dirname(__file__)
lic=p+"/"+A+".lic"
dat=p+"/"+A+".dat"
h2=p+"/"+A+".hash2"
keyf=p+"/"+A+".key"

if not os.path.exists(lic) or not os.path.exists(dat) or not os.path.exists(h2) or not os.path.exists(keyf):
    os._exit(1)

D=""

if hashlib.sha256(D.encode()).hexdigest()!=_u(open(lic).read()):
    os._exit(1)

if hashlib.sha256((D+"x").encode()).hexdigest()!=_u(open(h2).read()):
    os._exit(1)

cur=hashlib.sha256(open(__file__,"rb").read()).hexdigest()
sv=_u(open(dat).read())

if sv!="tmp" and cur!=sv:
    os._exit(1)

K=[50, 58, 127, 70, 250, 119, 111, 186, 48, 179, 86, 33, 45, 51, 80, 31, 131, 37, 158, 80, 195, 229, 41, 113, 200, 24, 84, 109, 18, 60, 68, 248]
K=bytes(K)

if hashlib.sha256(K).hexdigest()!=_u(open(keyf).read()):
    os._exit(1)

from Crypto.Cipher import AES
from Crypto.Util.Padding import unpad

def d(x):
    r=base64.b64decode(x)
    iv=r[:16]; mac=r[-32:]; e=r[16:-32]

    if not hmac.compare_digest(mac,hmac.new(K,iv+e,hashlib.sha256).digest()):
        os._exit(1)

    return unpad(AES.new(K,AES.MODE_CBC,iv).decrypt(e),16)

l2=base64.b64decode(D)
l1=d(l2.decode())
code=d(l1.decode())

exec(code.decode())
